import type { Observable, Subscription } from "rxjs";
import { map, merge, startWith, switchMap } from "rxjs";
import * as THREE from "three";

import type { Codable } from "./codable";
import type { ZenGardenObject } from "./object";
import type { RakePath, ZenGardenRakeStroke } from "./rake-stroke";
import type { Vector2Encoded } from "./vector2";
import { Vector2 } from "./vector2";

export type ZenGardenPlainEncoded = {
  size: Vector2Encoded;
};

const PLAIN_Z = 0;
const TEXTURE_RESOLUTION = 1024;
const TILE_SIZE = 2;

export class ZenGardenPlain implements Codable<ZenGardenPlainEncoded> {
  readonly object: THREE.Mesh;
  private material: THREE.MeshStandardMaterial;
  private subscription: Subscription | null = null;
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private texture: THREE.CanvasTexture;
  private gravelImage: HTMLImageElement | null = null;
  private _size: Vector2;

  constructor(encoded: ZenGardenPlainEncoded) {
    this._size = new Vector2(encoded.size);

    // Create canvas for compositing
    this.canvas = document.createElement("canvas");
    this.canvas.width = TEXTURE_RESOLUTION;
    this.canvas.height = TEXTURE_RESOLUTION;
    this.ctx = this.canvas.getContext("2d")!;
    this.texture = new THREE.CanvasTexture(this.canvas);

    // Load gravel image
    this.gravelImage = new Image();
    this.gravelImage.src = "/textures/gravel/color.jpg";
    this.gravelImage.onload = () => {
      this.renderTexture([]);
    };

    const geometry = new THREE.PlaneGeometry(1, 1);
    this.material = new THREE.MeshStandardMaterial({
      map: this.texture,
      roughness: 1,
    });

    this.object = new THREE.Mesh(geometry, this.material);
    this.object.position.z = PLAIN_Z;
    this.object.receiveShadow = true;
    this.object.scale.set(this._size.x, this._size.y, 1);
  }

  subscribeToRakeStrokes($objects: Observable<ZenGardenObject[]>): void {
    this.subscription?.unsubscribe();

    this.subscription = $objects.pipe(
      map(objects => objects.filter((o): o is ZenGardenRakeStroke => o instanceof ZenGardenRakeStroke)),
      switchMap(strokes => {
        if (strokes.length === 0) {
          return [strokes];
        }
        return merge(...strokes.map(s => s.$changed)).pipe(
          startWith(null),
          map(() => strokes),
        );
      }),
    ).subscribe(strokes => {
      this.renderTexture(strokes);
    });
  }

  private renderTexture(rakeStrokes: ZenGardenRakeStroke[]): void {
    const ctx = this.ctx;
    const w = TEXTURE_RESOLUTION;
    const h = TEXTURE_RESOLUTION;

    // Draw tiled gravel background
    if (this.gravelImage?.complete) {
      const tilesX = Math.ceil(this._size.x / TILE_SIZE);
      const tilesY = Math.ceil(this._size.y / TILE_SIZE);
      const tileW = w / tilesX;
      const tileH = h / tilesY;

      for (let y = 0; y < tilesY; y++) {
        for (let x = 0; x < tilesX; x++) {
          ctx.drawImage(this.gravelImage, x * tileW, y * tileH, tileW, tileH);
        }
      }
    } else {
      ctx.fillStyle = "#d4c4a8";
      ctx.fillRect(0, 0, w, h);
    }

    // Draw rake strokes as darker areas
    ctx.fillStyle = "rgba(0, 0, 0, 0.3)";
    ctx.strokeStyle = "rgba(0, 0, 0, 0.3)";

    for (const stroke of rakeStrokes) {
      this.drawRakeStroke(ctx, stroke, w, h);
    }

    this.texture.needsUpdate = true;
  }

  private drawRakeStroke(
    ctx: CanvasRenderingContext2D,
    stroke: ZenGardenRakeStroke,
    w: number,
    h: number,
  ): void {
    const path = stroke.serialize().path;
    const width = stroke.width;

    // Convert world coords to canvas coords (account for aspect ratio)
    const toCanvasX = (x: number) => ((x / this._size.x) + 0.5) * w;
    const toCanvasY = (y: number) => (0.5 - (y / this._size.y)) * h;
    const scaleX = w / this._size.x;
    const scaleY = h / this._size.y;

    ctx.lineWidth = width * Math.min(scaleX, scaleY);
    ctx.lineCap = "round";
    ctx.lineJoin = "round";

    switch (path.type) {
    case "circle":
      // Draw ellipse to account for aspect ratio
      ctx.beginPath();
      ctx.ellipse(
        toCanvasX(path.center.x),
        toCanvasY(path.center.y),
        path.radius * scaleX,
        path.radius * scaleY,
        0,
        0,
        Math.PI * 2,
      );
      ctx.stroke();
      break;

    case "points":
      if (path.points.length < 2) return;
      this.drawSmoothPath(ctx, path, toCanvasX, toCanvasY);
      break;
    }
  }

  private drawSmoothPath(
    ctx: CanvasRenderingContext2D,
    path: Extract<RakePath, { type: "points" }>,
    toCanvasX: (x: number) => number,
    toCanvasY: (y: number) => number,
  ): void {
    const points = path.points.map(p => ({
      x: toCanvasX(p.x),
      y: toCanvasY(p.y),
    }));

    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);

    // Use quadratic curves for smooth path
    for (let i = 1; i < points.length - 1; i++) {
      const midX = (points[i].x + points[i + 1].x) / 2;
      const midY = (points[i].y + points[i + 1].y) / 2;
      ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY);
    }

    // Last point
    const last = points[points.length - 1];
    ctx.lineTo(last.x, last.y);

    if (path.closed) {
      ctx.closePath();
    }

    ctx.stroke();
  }

  dispose(): void {
    this.subscription?.unsubscribe();
    this.texture.dispose();
    this.material.dispose();
  }

  get size(): Vector2 {
    return this._size.clone();
  }

  set size(value: Vector2) {
    this._size = value.clone();
    this.object.scale.set(value.x, value.y, 1);
  }

  serialize(): ZenGardenPlainEncoded {
    return {
      size: this._size.serialize(),
    };
  }
}
